const payload = $json.body ?? $json;
const message = String(payload.message ?? '').trim();
const parts = Object.fromEntries(new Intl.DateTimeFormat('sv-SE', { timeZone: 'Asia/Seoul', year: 'numeric', month: '2-digit', day: '2-digit' }).formatToParts(new Date()).filter((part) => part.type !== 'literal').map((part) => [part.type, part.value]));
const dateLabel = `${parts.year}-${parts.month}-${parts.day}`;
return [{ json: { message, channel: String(payload.channel ?? 'unknown'), session_id: payload.session_id ?? null, user_id: payload.user_id ?? null, timezone: 'Asia/Seoul', timeMin: `${dateLabel}T00:00:00+09:00`, timeMax: `${dateLabel}T23:59:59+09:00` } }];

const events = $input.all().map((item) => item.json).filter((event) => event && (event.summary || event.start || event.id));
const formatTime = (value) => new Intl.DateTimeFormat('ko-KR', { timeZone: 'Asia/Seoul', hour: '2-digit', minute: '2-digit', hour12: false }).format(new Date(value));
if (!events.length) {
  return [{ json: { reply: '오늘 등록된 일정이 없습니다.', action: 'calendar-summary', count: 0 } }];
}
const lines = events.slice(0, 5).map((event) => {
  const title = event.summary || '제목 없는 일정';
  const allDay = Boolean(event.start?.date) && !event.start?.dateTime;
  if (allDay) {
    return `종일 ${title}`;
  }
  const start = event.start?.dateTime ? formatTime(event.start.dateTime) : '';
  const end = event.end?.dateTime ? formatTime(event.end.dateTime) : '';
  return end ? `${start}-${end} ${title}` : `${start} ${title}`;
});
const extra = events.length > 5 ? ` 외 ${events.length - 5}건` : '';
return [{ json: { reply: `오늘 일정은 ${lines.join(', ')}${extra}입니다.`, action: 'calendar-summary', count: events.length } }];
